PRAGMA defer_foreign_keys=TRUE;
CREATE TABLE levels (
  id TEXT PRIMARY KEY,
  hkgd_rank INTEGER,
  aredl_rank INTEGER,
  pemonlist_rank INTEGER,
  name TEXT NOT NULL,
  creator TEXT NOT NULL,
  verifier TEXT NOT NULL,
  level_id TEXT NOT NULL,
  description TEXT,
  thumbnail TEXT,
  song_id TEXT,
  song_name TEXT,
  tags TEXT,
  date_added TEXT,
  pack TEXT,
  gddl_tier INTEGER,
  nlw_tier TEXT
, list_points REAL NOT NULL DEFAULT 0, edel_enjoyment REAL);
CREATE TABLE records (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  level_id TEXT NOT NULL,
  player TEXT NOT NULL,
  date TEXT NOT NULL,
  video_url TEXT,
  fps TEXT,
  cbf INTEGER DEFAULT 0,
  attempts INTEGER, mode TEXT DEFAULT 'classic',
  FOREIGN KEY (level_id) REFERENCES levels(id) ON DELETE CASCADE
);
CREATE TABLE changelog (
  id TEXT PRIMARY KEY,
  date TEXT NOT NULL,
  level_name TEXT NOT NULL,
  level_id TEXT NOT NULL,
  change_type TEXT NOT NULL,
  old_rank INTEGER,
  new_rank INTEGER,
  description TEXT NOT NULL,
  list_type TEXT DEFAULT 'classic'
);
CREATE TABLE members (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  name TEXT UNIQUE NOT NULL,
  country TEXT,
  levels_beaten INTEGER NOT NULL DEFAULT 0,
  avatar TEXT
);
CREATE TABLE pending_submissions (
  id TEXT PRIMARY KEY,
  level_id TEXT NOT NULL,
  level_name TEXT,
  is_new_level INTEGER DEFAULT 0,
  record_data TEXT NOT NULL,
  level_data TEXT,
  submitted_at TEXT NOT NULL,
  submitted_by TEXT NOT NULL,
  status TEXT NOT NULL DEFAULT 'pending'
, is_platformer INTEGER DEFAULT 0, admin_decides_difficulty INTEGER DEFAULT 0);
CREATE TABLE website_content (
  id TEXT PRIMARY KEY,
  content_json TEXT NOT NULL,
  updated_at TEXT NOT NULL
);
CREATE TABLE ip_bans (
  ip TEXT PRIMARY KEY,
  attempts INTEGER DEFAULT 0,
  banned_until INTEGER DEFAULT 0,
  updated_at INTEGER
);
CREATE TABLE settings (key TEXT PRIMARY KEY, value TEXT NOT NULL, updated_at TEXT NOT NULL);
CREATE TABLE suggestions (
  id TEXT PRIMARY KEY,
  type TEXT NOT NULL DEFAULT 'issue',
  title TEXT NOT NULL,
  description TEXT NOT NULL,
  level_id TEXT,
  level_name TEXT,
  submitted_by TEXT,
  submitted_at TEXT NOT NULL,
  status TEXT NOT NULL DEFAULT 'pending',
  admin_notes TEXT,
  resolved_at TEXT,
  resolved_by TEXT
);
CREATE TABLE player_mappings (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    game_name TEXT NOT NULL,
    db_name TEXT NOT NULL,
    account_id INTEGER,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    UNIQUE(game_name)
);
CREATE TABLE platformer_levels (
    id TEXT PRIMARY KEY,
    hkgd_rank INTEGER,
    pemonlist_rank INTEGER,
    name TEXT NOT NULL,
    creator TEXT NOT NULL,
    verifier TEXT,
    level_id TEXT,
    description TEXT,
    thumbnail TEXT,
    song_id TEXT,
    song_name TEXT,
    tags TEXT,
    date_added TEXT,
    pack TEXT,
    difficulty INTEGER,
    created_at TEXT DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE platformer_records (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    level_id TEXT NOT NULL,
    player TEXT NOT NULL,
    date TEXT NOT NULL,
    video_url TEXT,
    fps TEXT,
    cbf INTEGER DEFAULT 0,
    attempts INTEGER,
    created_at TEXT DEFAULT CURRENT_TIMESTAMP,
    FOREIGN KEY (level_id) REFERENCES platformer_levels(id) ON DELETE CASCADE
);
DELETE FROM sqlite_sequence;
CREATE INDEX idx_levels_hkgd_rank ON levels(hkgd_rank);
CREATE INDEX idx_records_level_id ON records(level_id);
CREATE INDEX idx_changelog_date ON changelog(date DESC);
CREATE INDEX idx_members_levels ON members(levels_beaten DESC);
CREATE INDEX idx_suggestions_status ON suggestions(status);
CREATE INDEX idx_suggestions_date ON suggestions(submitted_at DESC);
CREATE INDEX idx_player_mappings_game_name ON player_mappings(game_name);
CREATE INDEX idx_player_mappings_db_name ON player_mappings(db_name);
CREATE INDEX idx_platformer_records_level_id ON platformer_records(level_id);
CREATE INDEX idx_pending_submissions_platformer ON pending_submissions(is_platformer);
CREATE INDEX idx_pending_submissions_admin_decides ON pending_submissions(admin_decides_difficulty);
