INSERT INTO "levels" ("id","hkgd_rank","aredl_rank","pemonlist_rank","name","creator","verifier","level_id","description","thumbnail","song_id","song_name","tags","date_added","pack","gddl_tier","nlw_tier","list_points","edel_enjoyment") VALUES('hkgd-4',4,150,NULL,'ConClusion','DreamZoneGD','BrowarKedawar','96471171',replace('The final and hardest level of the ConTrilogy. This level holds nothing back and utilizes memory to its fullest while including flashbacks from both ConTroller and ConFusion. The wave part is known for being very intimidating to approach and can be considered one of the most intense parts of a memory level. Now, can you escape your mind and conclude this nightmare once and for all?\n','\n',char(10)),'https://levelthumbs.prevter.me/thumbnail/96471171','219635','-Control: Mind- by Waterflame','["2.1","Long","Fast-paced","Timings","Memory","Precision"]','25/05/20',NULL,34,NULL,0,83.25);
INSERT INTO "levels" ("id","hkgd_rank","aredl_rank","pemonlist_rank","name","creator","verifier","level_id","description","thumbnail","song_id","song_name","tags","date_added","pack","gddl_tier","nlw_tier","list_points","edel_enjoyment") VALUES('hkgd-5',5,158,NULL,'Crimson Planet','TrueOmega','rWooshi','45866767','Legendary former top 1 with an intense dubstep song and a loose otherworldly theme. Incredibly reminiscent of early 2.1, being started only months after 2.1''s release. Includes Terron''s iconic part repurposed from Yatagarasu and a modern endscreen. Took too long to get rated. Do not abbreviate on Discord (seriously).','https://levelthumbs.prevter.me/thumbnail/45866767','530913','Wonderpunch by Xtrullor','["Long","High Cps","2.1","Wave"]','25/07/10',NULL,33.625,'Excruciating',0,55);
